import{_ as a,n as l,p as e,Y as i}from"./chunks/framework.KP8KjELV.js";const u=JSON.parse('{"title":"技术管理应该做什么，不应该做什么","description":"技术管理应该做什么，不应该做什么","frontmatter":{"date":"2023-02-14T00:00:00.000Z","head":[["meta",{"name":"description","content":"技术管理应该做什么，不应该做什么"}],["meta",{"name":"keywords","content":"技术管理,管理"}]]},"headers":[],"relativePath":"Blog/2023/1.技术管理应该做什么不该做什么.md","filePath":"Blog/2023/1.技术管理应该做什么不该做什么.md","lastUpdated":1703840066000}'),t={name:"Blog/2023/1.技术管理应该做什么不该做什么.md"},p=i('<h1 id="技术管理应该做什么-不应该做什么" tabindex="-1">技术管理应该做什么，不应该做什么 <a class="header-anchor" href="#技术管理应该做什么-不应该做什么" aria-label="Permalink to &quot;技术管理应该做什么，不应该做什么&quot;">​</a></h1><h2 id="应该做" tabindex="-1">应该做 <a class="header-anchor" href="#应该做" aria-label="Permalink to &quot;应该做&quot;">​</a></h2><ul><li><p>保持技术热枕</p><p>技术管理者需要对技术趋势做出适时准确的判断，需要一定技术水平来支撑。在主要应用的技术领域保持深度，在整个技术体系中保持一定广度。</p><p>不能因为涉足管理就停止对技术的学习，但也要在技术与管理中做好平衡。技术管理者的时间碎片化往往更严重。要做一些适于个人的改变，利用零散时间来给自己在技术上“充电”。不过这往往也要付出更多额外的精力。</p></li><li><p>重视技术和经验分享</p><p>在开发中对成员倾尽所能的指导。总结会中讨论记录下存在的问题，整理项目中沉淀的技术。有助于团队整体水平的提高，使整个团队的技术水平发展行程良性的循环。</p></li><li><p>严格要求</p><p>人是惰性的，必须建立一些规矩，以规范流程，保质提效。但不要强用管理的权力约束他人，在管理上少一点技巧多一点真诚，与被管理者建立起信任的纽带，或许能取得更好的效果。</p><p>如果问题出在人员身上，也要有足够的魄力去反馈乃至洗牌换人。</p></li><li><p>慎独</p><p>严格要求了他人也要严格要求自己，慎独也就是谨慎的对待自己独处的情况。成为技术管理者后“独处”的情况会更多，心态也难免会有所变化。从开发者到技术管理者，最核心的变化是从管理自我到管理他人。那首先我们应该做好自我的管理，自己做到了，才能有底气和实力去通过一些恰当的方式去管理和引导他人。</p></li></ul><h2 id="不应该做" tabindex="-1">不应该做 <a class="header-anchor" href="#不应该做" aria-label="Permalink to &quot;不应该做&quot;">​</a></h2><ul><li><p>技术热情过重</p><p>所有的技术细节都要参与讨论和最后拍板，反而会成为团队决策的瓶颈。</p></li><li><p>丢掉技术</p><p>随着管理涉足的深入可能会对技术的需求逐步递减。但不应丢掉技术，这里与上面提到的保持技术热枕对应。一个技术 leader 如果有扎实的基础，持续对技术保持跟进，一是会起到非常好的带头作用，二是跟开发者沟通进展会顺利很多,最后有良好的技术视野才能更好的做技术规划。毕竟精力是有限的，根据工作的重心控制好平衡。</p></li><li><p>只分配工作</p><p>技术管理不只是分配工作，是对既有信息和有限资源进行分配和引导来解决问题达成目标。也需要多跟产品及开发探讨任务本身，引导大家思考需求的合理性和可靠的实施方案。</p></li><li><p>被动管理</p><p>不要有了问题才处理。做管理本身就不能待在思想舒适区，处在一个相对静态的心理背景下，思想上需要适应这种每天处理各种问题的节奏，如果总是被动管理，心理上也会产生排斥，只会觉得那些琐事，越来越烦，内心越来越挣扎。只有主动出击，真的推动事情、解决问题的时候，才能体会到成就感，从中找到乐趣。</p></li></ul><p>以上简单整理了搜集的内容和个人看法，希望能够对大家起到参考帮助的作用，在工作进行中还是要根据个人和团队的实际情况来实施。</p><p>大家作为开发也是经过了新手到老手的过程，在技术管理的工作中也是一样，也会有一个沉淀的过程。遇到问题沉着冷静积极应对。不断在过程中总结经验，才能在技术管理的工作当中逐渐得心应手。</p><h2 id="跟一波风-补充来自-chatgpt-的回答" tabindex="-1">跟一波风，补充来自 chatGPT 的回答 <a class="header-anchor" href="#跟一波风-补充来自-chatgpt-的回答" aria-label="Permalink to &quot;跟一波风，补充来自 chatGPT 的回答&quot;">​</a></h2><p>技术管理是指在技术领域中担任管理角色的人员。下面列出了技术管理应该做和不应该做的一些事项：</p><p>技术管理应该做的：</p><ol><li>制定技术战略和规划：技术管理应该参与制定公司的技术战略和规划，以确保技术的发展与公司的发展保持一致。</li><li>管理技术团队：技术管理应该招聘、培训和管理技术团队，确保团队成员的工作效率和技能水平。</li><li>确定项目目标和计划：技术管理应该与其他部门合作，确定项目的目标和计划，并监督项目的进度和成果。</li><li>优化技术流程：技术管理应该不断寻找和实施新的技术工具和流程，以提高团队的工作效率和生产力。</li><li>沟通协调：技术管理应该与其他部门和团队进行良好的沟通和协调，以确保技术工作与公司的战略和目标保持一致。</li></ol><p>技术管理不应该做的：</p><ol><li>过分干涉技术细节：技术管理不应该过分干涉团队的技术细节，而应该尊重团队成员的专业知识和技术判断。</li><li>忽视员工反馈：技术管理不应该忽视员工的反馈和意见，而应该倾听和尊重团队成员的意见和建议。</li><li>缺乏透明度和沟通：技术管理不应该缺乏透明度和沟通，而应该及时向团队成员和其他部门反馈项目的进展和成果。</li><li>忽视团队成员的职业发展：技术管理不应该忽视团队成员的职业发展，而应该提供培训和晋升机会，以激励团队成员的积极性和创造力。</li><li>忽视公司战略和目标：技术管理不应该忽视公司的战略和目标，而应该将技术工作与公司的战略和目标紧密结合起来，以确保技术的发展与公司的发展保持一致。</li></ol>',13),o=[p];function _(r,n,c,d,s,h){return l(),e("div",null,o)}const f=a(t,[["render",_]]);export{u as __pageData,f as default};
